import { ZIndex, ZIndexType } from '@components/z-index';
import { cn } from '@utils/cn';
import { createThrottle } from '@utils/helper';
import X from 'lucide-solid/icons/x';
import { createEffect, createSignal, For, mergeProps, onCleanup, onMount, Show } from 'solid-js';
import { TourAPI, TourPlacement, TourProps, TourStep } from './tour.types';

interface SpotlightRect {
  top: number;
  left: number;
  width: number;
  height: number;
}

function getElementRect(targetId: string, padding: number): SpotlightRect | null {
  const el = document.getElementById(targetId);
  if (!el) return null;
  const rect = el.getBoundingClientRect();
  return {
    top: rect.top - padding,
    left: rect.left - padding,
    width: rect.width + padding * 2,
    height: rect.height + padding * 2,
  };
}

function buildClipPath(rect: SpotlightRect): string {
  const { top, left, width, height } = rect;
  const right = left + width;
  const bottom = top + height;

  return `polygon(
    0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 0%,
    ${left}px ${top}px,
    ${left}px ${bottom}px,
    ${right}px ${bottom}px,
    ${right}px ${top}px,
    ${left}px ${top}px
  )`;
}

interface PopupPosition {
  top: number;
  left: number;
  arrowOffset: string;
}

const POPUP_MARGIN = 12;
const POPUP_WIDTH = 340;

function computePopupPosition(
  spotRect: SpotlightRect,
  placement: TourPlacement,
  popupHeight: number,
): PopupPosition {
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  const { top, left, width, height } = spotRect;
  let pTop = 0;
  let pLeft = 0;
  let arrowOffset = '50%';

  const centerX = left + width / 2;
  const centerY = top + height / 2;

  switch (placement) {
    case 'bottom':
    case 'bottom-start':
    case 'bottom-end':
      pTop = top + height + POPUP_MARGIN;
      pLeft =
        placement === 'bottom-start'
          ? left
          : placement === 'bottom-end'
            ? left + width - POPUP_WIDTH
            : centerX - POPUP_WIDTH / 2;
      arrowOffset = `${centerX - Math.max(16, Math.min(pLeft, pLeft))}px`;
      break;

    case 'top':
    case 'top-start':
    case 'top-end':
      pTop = top - popupHeight - POPUP_MARGIN;
      pLeft =
        placement === 'top-start'
          ? left
          : placement === 'top-end'
            ? left + width - POPUP_WIDTH
            : centerX - POPUP_WIDTH / 2;
      arrowOffset = `${centerX - Math.max(16, Math.min(pLeft, pLeft))}px`;
      break;

    case 'left':
    case 'left-start':
    case 'left-end':
      pTop =
        placement === 'left-start'
          ? top
          : placement === 'left-end'
            ? top + height - popupHeight
            : centerY - popupHeight / 2;
      pLeft = left - POPUP_WIDTH - POPUP_MARGIN;
      arrowOffset = `${centerY - pTop}px`;
      break;

    case 'right':
    case 'right-start':
    case 'right-end':
      pTop =
        placement === 'right-start'
          ? top
          : placement === 'right-end'
            ? top + height - popupHeight
            : centerY - popupHeight / 2;
      pLeft = left + width + POPUP_MARGIN;
      arrowOffset = `${centerY - pTop}px`;
      break;
  }

  pLeft = Math.max(16, Math.min(pLeft, vw - POPUP_WIDTH - 16));
  pTop = Math.max(16, Math.min(pTop, vh - popupHeight - 16));

  return { top: pTop, left: pLeft, arrowOffset };
}

interface InternalTourProps extends TourProps {
  activeStep: () => number;
  visible: () => boolean;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
}

const TourComponent = (rawProps: InternalTourProps) => {
  const props = mergeProps(
    {
      showClose: true,
      showProgress: true,
      maskClosable: false,
      prevLabel: 'Prev',
      nextLabel: 'Next',
      doneLabel: 'Done',
    },
    rawProps,
  );

  const [spotRect, setSpotRect] = createSignal<SpotlightRect>({
    top: 0,
    left: 0,
    width: 0,
    height: 0,
  });
  const [popupPos, setPopupPos] = createSignal<PopupPosition>({
    top: 0,
    left: 0,
    arrowOffset: '50%',
  });
  const [popupHeight, setPopupHeight] = createSignal(200);

  let popupRef: HTMLDivElement | undefined;

  const currentStep = (): TourStep | undefined => props.steps[props.activeStep()];
  const isLastStep = () => props.activeStep() === props.steps.length - 1;

  function recalculate() {
    const step = currentStep();
    if (!step) return;

    const padding = step.spotlightPadding ?? 8;
    const placement = step.placement ?? 'bottom';
    const ph = popupRef?.offsetHeight ?? popupHeight();

    const rect = getElementRect(step.target, padding);
    if (!rect) return;
    setSpotRect(rect);
    setPopupPos(computePopupPosition(rect, placement, ph));
  }

  const throttledRecalc = createThrottle(recalculate, 60);

  createEffect(function trackStepChange() {
    if (!props.visible()) return;

    const _step = props.activeStep();
    void _step;

    const step = currentStep();
    if (step?.target) {
      const el = document.getElementById(step.target);
      el?.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    }

    let timer: ReturnType<typeof setTimeout> | undefined = setTimeout(() => {
      timer = undefined;
      if (popupRef) setPopupHeight(popupRef.offsetHeight);
      recalculate();
    }, 80);
    onCleanup(function cancelStepTimer() {
      if (timer !== undefined) {
        clearTimeout(timer);
        timer = undefined;
      }
    });
  });

  onMount(function registerResizeListener() {
    window.addEventListener('resize', throttledRecalc);
    window.addEventListener('scroll', throttledRecalc, true);
    onCleanup(function removeResizeListener() {
      window.removeEventListener('resize', throttledRecalc);
      window.removeEventListener('scroll', throttledRecalc, true);
      throttledRecalc.cancel();
    });
  });

  const maskStyle = () => ({ 'clip-path': buildClipPath(spotRect()) });

  const popupStyle = () => {
    const { top, left, arrowOffset } = popupPos();
    return {
      top: `${top}px`,
      left: `${left}px`,
      width: `${POPUP_WIDTH}px`,
      '--arrow-offset': arrowOffset,
    };
  };

  const handleMaskClick = () => {
    if (props.maskClosable) props.onClose();
  };

  return (
    <ZIndex type={ZIndexType.OVERLAY} open={props.visible()} blockScroll>
      <div class={cn('tr01', props.class?.mask)} onClick={handleMaskClick} />

      <div class={cn('tr02', props.class?.spotlight)} style={maskStyle()} />

      <div
        ref={popupRef}
        class={cn('tr03', props.class?.popup)}
        style={popupStyle()}
        data-placement={currentStep()?.placement ?? 'bottom'}
      >
        <div class={cn('tr04', props.class?.header)}>
          <span class="tr04-title">{currentStep()?.title}</span>
          <Show when={props.showClose}>
            <button class="tr04-close" onClick={props.onClose} aria-label="Close tour">
              <X size={14} />
            </button>
          </Show>
        </div>

        <Show when={currentStep()?.content}>
          <div class={cn('tr05', props.class?.body)}>{currentStep()?.content}</div>
        </Show>

        <Show
          when={!currentStep()?.footer}
          fallback={<div class={cn('tr06', props.class?.footer)}>{currentStep()?.footer}</div>}
        >
          <div class={cn('tr06', props.class?.footer)}>
            <Show when={props.showProgress}>
              <div class={cn('tr07', props.class?.progress)}>
                <For each={props.steps}>
                  {(_, i) => (
                    <span class={cn('tr07-dot', i() === props.activeStep() && 'active')} />
                  )}
                </For>
              </div>
            </Show>

            <div class="ml-auto flex gap-2">
              <Show when={props.activeStep() > 0}>
                <button class="btn btn-sm btn-ghost" onClick={props.onPrev}>
                  {props.prevLabel}
                </button>
              </Show>
              <button
                class="btn btn-sm btn-primary"
                onClick={isLastStep() ? props.onClose : props.onNext}
              >
                {isLastStep() ? props.doneLabel : props.nextLabel}
              </button>
            </div>
          </div>
        </Show>
      </div>
    </ZIndex>
  );
};

export function createTour(tourProps: TourProps): [TourAPI, () => import('solid-js').JSX.Element] {
  const [activeStep, setActiveStep] = createSignal(0);
  const [visible, setVisible] = createSignal(false);

  function start(stepIndex = 0) {
    setActiveStep(stepIndex);
    setVisible(true);
    tourProps.steps[stepIndex]?.onEnter?.(stepIndex);
    tourProps.onStepChange?.(stepIndex);
  }

  function stop() {
    const step = activeStep();
    tourProps.steps[step]?.onLeave?.(step);
    setVisible(false);
    tourProps.onClose?.(step);
  }

  function next() {
    const cur = activeStep();
    tourProps.steps[cur]?.onLeave?.(cur);
    const nextStep = cur + 1;
    if (nextStep >= tourProps.steps.length) {
      setVisible(false);
      tourProps.onFinish?.();
      return;
    }
    setActiveStep(nextStep);
    tourProps.steps[nextStep]?.onEnter?.(nextStep);
    tourProps.onStepChange?.(nextStep);
  }

  function prev() {
    const cur = activeStep();
    if (cur <= 0) return;
    tourProps.steps[cur]?.onLeave?.(cur);
    const prevStep = cur - 1;
    setActiveStep(prevStep);
    tourProps.steps[prevStep]?.onEnter?.(prevStep);
    tourProps.onStepChange?.(prevStep);
  }

  function goTo(stepIndex: number) {
    if (stepIndex < 0 || stepIndex >= tourProps.steps.length) return;
    const cur = activeStep();
    tourProps.steps[cur]?.onLeave?.(cur);
    setActiveStep(stepIndex);
    tourProps.steps[stepIndex]?.onEnter?.(stepIndex);
    tourProps.onStepChange?.(stepIndex);
  }

  const api: TourAPI = {
    start,
    stop,
    next,
    prev,
    goTo,
    isActive: visible,
    currentStep: activeStep,
  };

  const TourRenderer = () => (
    <TourComponent
      {...tourProps}
      activeStep={activeStep}
      visible={visible}
      onClose={stop}
      onNext={next}
      onPrev={prev}
    />
  );

  return [api, TourRenderer];
}
